//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Run fonts and complex-script property splitting (rFonts slots, cs,
//! *Cs pairing)".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from ECMA-376 /
//! ISO 29500-1, MS-OI29500, and the normative schemas. A FAILING assertion here
//! means stemma DIVERGES from Microsoft Word's documented behaviour — i.e. a
//! real Word-compliance GAP — NOT a test to be weakened until it passes.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So for these (unedited) documents we assert on the CONSUMPTION
//! side — `read_accepted()`/`read_rejected()` text — and on opens-clean
//! validity, never on re-serialized XML for "Word ignores value V on layout"
//! claims (font-slot arbitration is render-only; it never rewrites stored text).

use std::io::Read;

use stemma::api::{Document, validate};

// ─── Prelude: minimal .docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// package parts as `(part_name, xml)`; for each one ending in a known
/// WordprocessingML part name we add the matching content-type override and a
/// document rel.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides + document rels for any extra parts we recognise.
    let mut overrides = String::new();
    let mut doc_rels_extra = String::new();
    for (rel_seq, (part, _xml)) in (1..).zip(extra_parts.iter()) {
        let (ct, rel_type) = if part.ends_with("styles.xml") {
            (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
            )
        } else if part.ends_with("numbering.xml") {
            (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
            )
        } else {
            panic!("make_docx: unrecognised extra part {part} — extend the override map");
        };
        // Part names in [Content_Types].xml overrides are absolute ("/word/..").
        let part_abs = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_abs}" ContentType="{ct}"/>"#
        ));
        // Document rels target is relative to word/ (e.g. "styles.xml").
        let target = part.trim_start_matches("word/").trim_start_matches('/');
        doc_rels_extra.push_str(&format!(
            r#"<Relationship Id="rIdX{rel_seq}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_extra}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return its `word/document.xml`.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse, re-serialize with default export options, and return the resulting
/// `word/document.xml`. NOTE: for an UNEDITED document this reflects stemma's
/// verbatim-preservation contract, not Word normalization (see header).
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert that `validate` reports no errors (opens-clean).
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = validate(bytes);
    assert!(report.ok, "{msg} — validation issues: {:?}", report.issues);
}

/// Reject-all text.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

/// Accept-all text.
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

