#[test]
fn rtl_forces_all_chars_into_cs_slot_text_preserved() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:cs="Times New Roman"/><w:rtl/></w:rPr><w:t xml:space="preserve">English العربية </w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        reject_text(&b).trim(),
        "English العربية".trim(),
        "Slot selection under rtl is render-only (MS-OI §2.1.88; §17.3.2.26/.30); it must not alter stored text — reject-all reproduces the run text verbatim."
    );
    assert_eq!(
        accept_text(&b).trim(),
        "English العربية".trim(),
        "No tracked change present; font-slot routing changes glyphs not characters — accept-all yields identical text (§17.3.2.26/.30, MS-OI §2.1.88)."
    );
    assert_opens_clean(
        &b,
        "rFonts ascii+cs plus w:rtl toggle is schema-valid CT_RPr; Word opens without repair (§17.3.2.26, §17.3.2.30).",
    );
}

#[test]
fn no_rfonts_default_font_is_times_new_roman_text_preserved() {
    let body = r#"<w:p><w:r><w:t>plain</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        reject_text(&b).trim(),
        "plain".trim(),
        "No rFonts: run text unchanged; the default-font fill-in (TNR) is render-only — reject-all reproduces 'plain' verbatim (§17.3.2.26, MS-OI §2.1.88)."
    );
    assert_opens_clean(
        &b,
        "A run with no rFonts is schema-valid; Word opens without repair and applies its TNR default at layout (§17.3.2.26, MS-OI §2.1.88).",
    );
}

#[test]
fn eastasia_classified_chars_escape_cs_rtl_slot() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New" w:eastAsia="MS Mincho" w:cs="Times New Roman" w:hint="eastAsia"/><w:bCs/><w:rtl/></w:rPr><w:t>English 中文</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "English 中文".trim(),
        "Slot selection (§17.3.2 ordered steps) is render-only: Latin 'English' (CS via rtl) and EA '中文' (East Asian via hint precedence) must both survive verbatim on the consumption view (§17.3.2.7)."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "English 中文".trim(),
        "No tracked revision; reject reproduces original text identically — font-slot arbitration must not corrupt/drop characters (§17.3.2, §17.3.2.7)."
    );
    assert_opens_clean(
        &b,
        "rFonts ascii/hAnsi/eastAsia/cs/hint + bCs + rtl is schema-valid CT_RPr; Word opens without repair (§17.3.2.7, §17.3.2.26).",
    );
}

#[test]
fn mixed_script_run_ascii_cs_slots_no_toggle() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:cs="Times New Roman"/></w:rPr><w:t>English العربية</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "English العربية".trim(),
        "Per §17.3.2 ascii vs cs slot choice is render-only; the run's mixed Latin+Arabic text must be reproduced verbatim regardless of font face mapping (§17.3.2.26)."
    );
    assert_opens_clean(
        &b,
        "rFonts carrying both ascii and cs typeface attributes (no toggle) is schema-valid CT_Fonts; Word opens without repair (§17.3.2.26).",
    );
}

#[test]
fn rtl_forces_all_chars_to_cs_slot_over_classification() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:cs="Times New Roman"/><w:rtl/></w:rPr><w:t>English العربية</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "English العربية".trim(),
        "rtl forces the CS slot for all chars (§17.3.2.30) but that is face-selection only; run text must be reproduced verbatim on the consumption view (§17.3.2)."
    );
    assert_opens_clean(
        &b,
        "rFonts ascii+cs combined with w:rtl in CT_RPr is schema-valid; Word opens without repair (§17.3.2.30, §17.3.2.26).",
    );
}

