fn ascii_asciitheme_ignore_is_per_element_only() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:asciiTheme="minorHAnsi"/></w:rPr><w:t>Sample</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "rFonts with both ascii and asciiTheme is schema-valid CT_Fonts; the literal-vs-theme 'ignore' is a within-element consumption arbitration, not a deletion — Word opens without repair (§17.3.2.26, MS-OI §2.1.88).",
    );
}

